package org.apache.commons.csv;

import org.junit.jupiter.api.Test;

import static org.junit.jupiter.api.Assertions.*;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    void testIsNullHandling_whenNullStringIsNull() throws Exception {
        CSVFormat format = CSVFormat.DEFAULT.withNullString(null);
        boolean result = format.isNullHandling();
        assertFalse(result);
    }

    @Test
    void testIsNullHandling_whenNullStringIsNonNull() throws Exception {
        // Using reflection to create a CSVFormat instance with nullString set to "NULL"
        CSVFormat format = CSVFormat.DEFAULT.withNullString("NULL");
        boolean result = format.isNullHandling();
        assertTrue(result);
    }
}
